/***************************************************************************
Supported Design File Formats: PNG, JPG,JPEG,AI,EPS,SVG,SVGZ
Documentation: https://docs.melcocloud.com/articles/auto-digitizing/number-of-colors
Supported Values for flatten_overlap: points 1 Inch=254
***************************************************************************/
{
  "conversion_params": {
    "auto_digitize_params": {
      "color_reduction_options": {
        "num_colors": 2
      }
    }
  },
  "design": {
    "type":"base64",
    "data": "{{COLORS_BASE64}}",
    "file_name": "colors.svg"
  },
  "output_file_name": "con_colors.svg"
}

/***************************************************************************
Supported Design File Formats: PNG, JPG,JPEG
Documentation: https://docs.melcocloud.com/articles/auto-digitizing/include-background-color
Supported Values for include_background_color: 
**************************************************************************
    DontInclude                 [Default]
    Include
    IncludeInteriorObjectsOnly
***************************************************************************/
{
    "conversion_params": {
        "auto_digitize_params": {
            "color_reduction_options": {
                "include_background_color": "DontInclude"  //See the Supported value list
            }
        }
    },
    "design":{
        "type":"base64",
        "data":"{{BG_BASE64}}",
        "file_name":"input.bmp"
    },
    "output_file_name":"output.svg"
}

/***************************************************************************
