***************************************************************************/
{
  "conversion_params": {
    "auto_digitize_params": {
      "color_reduction_options": {
        "override_colors": [
          {
            "b": 0,
            "g": 0,
            "r": 255
          },
          {
            "b": 0,
            "g": 255,
            "r": 0
          },
          {
            "b": 255,
            "g": 0,
            "r": 0
          }
        ]
      }
    }
  },
